import{_ as i,C as r,o as n,c as t,a7 as s,E as o}from"./chunks/framework.jppWPAGv.js";const f=JSON.parse('{"title":"EOPF Explorer Webinar #2 - Advanced Analysis with Sentinel Zarr","description":"","frontmatter":{"title":"EOPF Explorer Webinar #2 - Advanced Analysis with Sentinel Zarr","layout":"page"},"headers":[],"relativePath":"webinars-events/webinar-2-advanced-analysis.md","filePath":"webinars-events/webinar-2-advanced-analysis.md"}'),l={name:"webinars-events/webinar-2-advanced-analysis.md"};function d(p,e,c,h,u,b){const a=r("CTASection");return n(),t("div",null,[e[0]||(e[0]=s('<h1 id="eopf-explorer-webinar-2-advanced-analysis-with-sentinel-zarr" tabindex="-1">EOPF Explorer Webinar #2 - Advanced Analysis with Sentinel Zarr <a class="header-anchor link" href="#eopf-explorer-webinar-2-advanced-analysis-with-sentinel-zarr" aria-label="Permalink to &quot;EOPF Explorer Webinar #2 - Advanced Analysis with Sentinel Zarr&quot;">​</a></h1><div class="padding round margin-bottom row"><div class="max"><div>April 20, 2025 | 15:00-16:00 CET</div></div><a href="https://buytickets.at/thrivegeo/2073515/r/explorerweb" target="_blank" class="button primary">Register Now</a></div><p>While the first webinar focused on discovery and screening, this second one dives deeper into analysis workflows enabled by the EOPF Sentinel Zarr Explorer.</p><h3 id="what-you-ll-see-in-this-webinar" tabindex="-1">What you&#39;ll see in this webinar <a class="header-anchor link" href="#what-you-ll-see-in-this-webinar" aria-label="Permalink to &quot;What you&#39;ll see in this webinar&quot;">​</a></h3><p>We move beyond browsing and band combinations into:</p><ul><li><p>Online, in-browser analysis with cloud-native Sentinel Zarr</p></li><li><p>Moving from visual exploration to structured analytical workflows</p></li><li><p>Hands-on practice using openEO and openEO Studio for on-the-fly processing</p></li></ul><p>This session will demonstrate how the EOPF Explorer supports the full user journey, from initial discovery to actionable analysis, without requiring traditional download-heavy workflows.</p><h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor link" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>Zarr is the planned future distribution format for Copernicus Sentinel data.</p><p>The EOPF Explorer demonstrates how enhanced GeoZarr conventions unlock:</p><ul><li>Faster analysis directly in the browser</li><li>Scalable cloud-native processing</li><li>Reduced friction between exploration and insight</li><li>Open standards-based interoperability</li></ul><p>For developers, this means access to:</p><ul><li>Client-side rendering (OpenLayers + WebGL)</li><li>Server-side visualization (TiTiler)</li><li>Open specifications (STAC, GeoZarr conventions)</li></ul><p>For users and researchers, this means:</p><ul><li>Immediate analytical capability</li><li>Less overhead</li><li>Faster experimentation and iteration</li></ul><h3 id="who-should-attend" tabindex="-1">Who Should Attend <a class="header-anchor link" href="#who-should-attend" aria-label="Permalink to &quot;Who Should Attend&quot;">​</a></h3><ul><li>Earth observation data users and researchers</li><li>Data scientists interested in cloud-native workflows</li><li>Web developers creating geospatial applications</li><li>Anyone curious about the future of Copernicus data distribution</li></ul><h3 id="learn-more" tabindex="-1">Learn More <a class="header-anchor link" href="#learn-more" aria-label="Permalink to &quot;Learn More&quot;">​</a></h3><ul><li>Software and services: <a href="/pr-preview/pr-80/software-services/index" class="link">https://explorer.eopf.copernicus.eu/software-services</a></li><li>Data model: <a href="/pr-preview/pr-80/software-services/datamodel/index" class="link">https://explorer.eopf.copernicus.eu/software-services/datamodel/</a></li><li>Project site: <a href="/pr-preview/pr-80/" class="link">https://explorer.eopf.copernicus.eu/</a></li></ul><p>Be part of the conversation. Shape the future of Sentinel data use.</p><br>',21)),o(a,{style:{"margin-bottom":"0px"},title:"Join the discussion!",tagline:"We welcome your feedback and contributions.",primaryButton:"Visit the EOPF Forum",primaryLink:"https://discourse.eopf.copernicus.eu/c/eopf-explorer/17",dark:""})])}const v=i(l,[["render",d]]);export{f as __pageData,v as default};
